+++ b/src/shared/types.ts
@@ -0,0 +1,292 @@
+export type Provider = "openai" | "anthropic";
+export type Locale = "en" | "zh";
+
+export type MessageRole = "system" | "user" | "assistant";
+
+export type ChatMessage = {
+  role: MessageRole;
+  content: string;
+};
+
+export type ProviderSettings = {
+  id: string;
+  name: string;
+  provider: Provider;
+  apiKey: string;
+  baseUrl?: string;
+  models: string[];
+  defaultModel: string;
+  enabled: boolean;
+};
+
+export type ModelUsage = {
+  inputTokens?: number;
+  outputTokens?: number;
+  totalTokens?: number;
+};
+
+export type ModelRequest = {
+  messages: ChatMessage[];
+  model?: string;
+  maxTokens?: number;
+  temperature?: number;
+  timeoutMs?: number;
+};
+
+export type ModelResponse = {
+  provider: Provider;
+  model: string;
+  text: string;
+  usage?: ModelUsage;
+  raw?: unknown;
+};
+
+export type ModelGateway = {
+  chat(messages: ChatMessage[]): Promise<ModelResponse>;
+};
+
+export type Scope = "model.chat" | "page.read" | "page.act" | "agent.run" | "debugger.control";
+export type AgentControlMode = "dom" | "debugger" | "auto";
+export type AgentTaskIntent = "chat" | "run";
+
+export type SitePermission = {
+  origin: string;
+  appName?: string;
+  scopes: Scope[];
+  autoRun: boolean;
+  createdAt: string;
+  updatedAt: string;
+  lastUsedAt?: string;
+  revokedAt?: string;
+};
+
+export type CallSource = "sidebar" | "gateway";
+export type CallType = "access" | "chat" | "run";
+export type CallStatus = "success" | "failed" | "denied" | "canceled" | "revoked";
+
+export type CallLog = {
+  id: string;
+  source: CallSource;
+  origin?: string;
+  type: CallType;
+  model?: string;
+  status: CallStatus;
+  createdAt: string;
+  summary?: string;
+};
+
+export type DebugLog = {
+  id: string;
+  callId?: string;
+  createdAt: string;
+  title: string;
+  details: unknown;
+};
+
+export type GatewaySettings = {
+  enabled: boolean;
+};
+
+export type ExtensionSettings = {
+  locale: Locale;
+  providers: ProviderSettings[];
+  defaultProviderId?: string;
+  defaultModel?: string;
+  gateway: GatewaySettings;
+  skills: InstalledSkill[];
+  permissions: SitePermission[];
+  callLogs: CallLog[];
+  debugLogs: DebugLog[];
+};
+
+export type InteractiveElement = {
+  selector: string;
+  tagName: string;
+  label: string;
+  role?: string;
+};
+
+export type DomObservation = {
+  title: string;
+  url: string;
+  origin: string;
+  text: string;
+  selectedText?: string;
+  headings: string[];
+  links: Array<{ text: string; href: string }>;
+  interactiveElements: InteractiveElement[];
+};
+
+export type ConversationMemoryTurn = {
+  role: "user" | "assistant";
+  content: string;
+};
+
+export type ConversationMemory = {
+  turns: ConversationMemoryTurn[];
+};
+
+export type DomAction =
+  | { type: "click"; selector: string }
+  | { type: "type"; selector: string; value: string }
+  | { type: "scroll"; direction: "up" | "down"; amount?: number };
+
+export type AgentReadAction = { type: "read" };
+export type AgentDebuggerAction = { type: "debugger"; reason?: string };
+export type AgentSkillAction = { type: "skill"; skillId: string; input?: Record<string, unknown> };
+export type AgentAction = DomAction | AgentReadAction | AgentDebuggerAction | AgentSkillAction;
+export type AgentActionStatus = "success" | "failed" | "needs_confirmation" | "blocked";
+
+export type DomActionResult = {
+  ok: boolean;
+  status?: AgentActionStatus;
+  message: string;
+  skillDraft?: InstalledSkill;
+};
+
+export type DebuggerSnapshot = DomObservation & {
+  source: "debugger";
+  document?: unknown;
+  accessibilityTree?: unknown[];
+};
+
+export type DebuggerAction =
+  | { type: "attach" }
+  | { type: "detach" }
+  | { type: "snapshot" }
+  | { type: "screenshot"; fullPage?: boolean }
+  | { type: "click"; x: number; y: number }
+  | { type: "click"; selector: string }
+  | { type: "type"; text: string; selector?: string }
+  | { type: "scroll"; direction: "up" | "down"; amount?: number }
+  | { type: "wait"; ms?: number };
+
+export type DebuggerActionResult = {
+  ok: boolean;
+  message: string;
+  observation?: DebuggerSnapshot;
+  screenshot?: PageScreenshot;
+  rewrite?: PageRewriteResult;
+  formFill?: FormFillResult;
+};
+
+export type PageScreenshot = {
+  dataUrl: string;
+  mimeType: "image/png";
+  width: number;
+  height: number;
+  filename: string;
+};
+
+export type PageTextReplacement = {
+  index: number;
+  original: string;
+  replacement: string;
+};
+
+export type PageRewriteResult = {
+  sessionId: string;
+  changed: number;
+  replacements: PageTextReplacement[];
+};
+
+export type FormFillField = {
+  selector: string;
+  value: string;
+};
+
+export type FormFillResult = {
+  filled: number;
+  skipped: Array<{ selector: string; reason: string }>;
+};
+
+export type BenchmarkToolRequest =
+  | { type: "screenshot" }
+  | { type: "report" }
+  | { type: "rewrite"; instruction: string }
+  | { type: "restore-rewrite"; sessionId?: string }
+  | { type: "fill-form"; instruction: string };
+
+export type InstalledSkill = {
+  id: string;
+  name: string;
+  description: string;
+  skillMarkdown: string;
+  enabled: boolean;
+  source: "builtin" | "skills.sh" | "manual";
+  sourceUrl?: string;
+  installedAt?: string;
+  updatedAt?: string;
+};
+
+export type BenchmarkToolResult =
+  | { type: "screenshot"; title: string; screenshot: PageScreenshot }
+  | { type: "report"; title: string; html: string }
+  | { type: "rewrite"; title: string; rewrite: PageRewriteResult }
+  | { type: "restore-rewrite"; title: string; restored: number }
+  | { type: "fill-form"; title: string; formFill: FormFillResult };
+
+export type AgentEvent =
+  | { type: "observe"; observation: DomObservation }
+  | { type: "thought"; text: string; confidence?: number }
+  | { type: "plan"; text: string; confidence?: number }
+  | { type: "action"; action: AgentAction; reason: string; confidence?: number }
+  | { type: "action-result"; action: AgentAction; result: DomActionResult }
+  | { type: "blocked"; reason: string; status: "needs_confirmation" | "blocked" }
+  | { type: "final"; text: string };
+
+export type GatewayErrorCode =
+  | "permission_denied"
+  | "model_not_configured"
+  | "user_rejected"
+  | "gateway_disabled"
+  | "page_unavailable"
+  | "page_not_operable"
+  | "debugger_control_unavailable"
+  | "invalid_request"
+  | "internal_error";
+
+export type GatewayMethod = "requestAccess" | "getStatus" | "chat" | "run" | "models.list";
+
+export type BrowserAgentRequest =
+  | { id: string; requestId: string; source: "agenticify-page"; version: "1"; method: "requestAccess"; payload: AccessRequestPayload }
+  | { id: string; requestId: string; source: "agenticify-page"; version: "1"; method: "getStatus"; payload?: undefined }
+  | { id: string; requestId: string; source: "agenticify-page"; version: "1"; method: "chat"; payload: ChatPayload }
+  | { id: string; requestId: string; source: "agenticify-page"; version: "1"; method: "run"; payload: RunPayload }
+  | { id: string; requestId: string; source: "agenticify-page"; version: "1"; method: "models.list"; payload?: undefined };
+
+export type GatewayError = {
+  code: GatewayErrorCode;
+  message: string;
+  details?: unknown;
+};
+
+export type BrowserAgentResponse =
+  | { id: string; requestId: string; source: "agenticify-extension"; ok: true; result: unknown }
+  | { id: string; requestId: string; source: "agenticify-extension"; ok: false; code: GatewayErrorCode; error: GatewayError };
+
+export type AccessRequestPayload = {
+  appName?: string;
+  scopes: Scope[];
+  reason?: string;
+  autoRun?: boolean;
+};
+
+export type PendingAccessRequest = {
+  id: string;
+  origin: string;
+  appName?: string;
+  scopes: Scope[];
+  reason?: string;
+  requestedAutoRun: boolean;
+  createdAt: string;
+};
+
+export type ChatPayload = {
+  messages: ChatMessage[];
+};
+
+export type RunPayload = {
+  task: string;
+  mode?: AgentControlMode;
+};

diff --git a/src/agent/runtime.test.ts b/src/agent/runtime.test.ts
new file mode 100644
index 0000000..adabed4
--- /dev/null
+++ b/src/agent/runtime.test.ts
@@ -0,0 +1,255 @@
+import { describe, expect, it, vi } from "vitest";
+import type { DomObservation, ModelGateway } from "../shared/types";
+import { classifyTaskIntent, runAgentTask, runPageChat } from "./runtime";
+
+function observation(overrides: Partial<DomObservation> = {}): DomObservation {
+  return {
+    title: "Pricing",
+    url: "https://example.com/pricing",
+    origin: "https://example.com",
+    text: "Starter is $9. Pro is $29.",
+    headings: ["Pricing"],
+    links: [],
+    interactiveElements: [],
+    ...overrides
+  };
+}
+
+function gateway(...texts: string[]): ModelGateway {
+  return {
+    chat: vi.fn().mockImplementation(async () => ({
+      text: texts.shift() ?? JSON.stringify({ final: "Done.", reason: "No more work.", confidence: 0.9 }),
+      provider: "openai",
+      model: "gpt-4.1-mini"
+    }))
+  };
+}
+
+describe("Agent runtime", () => {
+  it("classifies simple questions as chat and operational requests as run", () => {
+    expect(classifyTaskIntent("What is the price on this page?")).toBe("chat");
+    expect(classifyTaskIntent("帮我总结一下这个页面")).toBe("chat");
+    expect(classifyTaskIntent("Click the buy button")).toBe("run");
+    expect(classifyTaskIntent("Fill the form with Ada's profile")).toBe("run");
+  });
+
+  it("answers simple page chat with page context and conversation memory", async () => {
+    const modelGateway = gateway("Starter costs $9.");
+
+    const result = await runPageChat({
+      task: "What about the previous answer?",
+      observation: observation(),
+      modelGateway,
+      memory: {
+        turns: [
+          { role: "user", content: "How much is Starter?" },
+          { role: "assistant", content: "Starter costs $9." }
+        ]
+      }
+    });
+
+    expect(result.finalText).toBe("Starter costs $9.");
+    expect(result.events.map((event) => event.type)).toEqual(["observe", "final"]);
+    expect(modelGateway.chat).toHaveBeenCalledWith(expect.arrayContaining([
+      expect.objectContaining({ role: "user", content: expect.stringContaining("Recent page conversation") })
+    ]));
+  });
+
+  it("answers page questions with observed page context in one turn", async () => {
+    const modelGateway = gateway(JSON.stringify({
+      final: "Starter costs $9.",
+      reason: "The page states the Starter price.",
+      confidence: 0.95
+    }));
+
+    const result = await runAgentTask({
+      task: "How much is Starter?",
+      observe: async () => observation(),
+      modelGateway,
+      maxSteps: 3
+    });
+
+    expect(result.finalText).toBe("Starter costs $9.");
+    expect(modelGateway.chat).toHaveBeenCalledWith(expect.arrayContaining([
+      expect.objectContaining({ role: "user", content: expect.stringContaining("Starter is $9") })
+    ]));
+    expect(result.events.map((event) => event.type)).toEqual(["observe", "thought", "final"]);
+  });
+
+  it("extracts final answers when the model wraps decision JSON in markdown", async () => {
+    const modelGateway = gateway([
+      "```json",
+      JSON.stringify({
+        final: "Starter costs $9.",
+        reason: "The page states the Starter price.",
+        confidence: 0.95
+      }),
+      "```"
+    ].join("\n"));
+
+    const result = await runAgentTask({
+      task: "How much is Starter?",
+      observe: async () => observation(),
+      modelGateway,
+      maxSteps: 3
+    });
+
+    expect(result.finalText).toBe("Starter costs $9.");
+    expect(result.events.at(-1)).toEqual({ type: "final", text: "Starter costs $9." });
+  });
+
+  it("extracts final answers when the model surrounds decision JSON with text", async () => {
+    const modelGateway = gateway(`Here is the answer:\n${JSON.stringify({
+      final: "Starter costs $9.",
+      reason: "The page states the Starter price.",
+      confidence: 0.95
+    })}`);
+
+    const result = await runAgentTask({
+      task: "How much is Starter?",
+      observe: async () => observation(),
+      modelGateway,
+      maxSteps: 3
+    });
+
+    expect(result.finalText).toBe("Starter costs $9.");
+  });
+
+  it("executes a DOM click when the model requests it", async () => {
+    const act = vi.fn().mockResolvedValue({ ok: true, status: "success", message: "Clicked #details" });
+    const modelGateway = gateway(
+      JSON.stringify({
+        action: { type: "click", selector: "#details" },
+        reason: "Open the details panel.",
+        confidence: 0.81
+      }),
+      JSON.stringify({
+        final: "The details panel is open.",
+        reason: "The requested click succeeded.",
+        confidence: 0.88
+      })
+    );
+
+    const result = await runAgentTask({
+      task: "Open details",
+      observe: vi.fn().mockResolvedValue(observation({
+        interactiveElements: [{ selector: "#details", tagName: "button", label: "Details" }]
+      })),
+      act,
+      modelGateway
+    });
+
+    expect(act).toHaveBeenCalledWith({ type: "click", selector: "#details" });
+    expect(result.finalText).toBe("The details panel is open.");
+    expect(result.events.map((event) => event.type)).toEqual([
+      "observe",
+      "thought",
+      "action",
+      "action-result",
+      "observe",
+      "thought",
+      "final"
+    ]);
+  });
+
+  it("injects matched skills into the model prompt and can execute skill actions", async () => {
+    const act = vi.fn().mockResolvedValue({ ok: true, status: "success", message: "Skill builtin/page-report completed" });
+    const modelGateway = gateway(
+      JSON.stringify({
+        action: { type: "skill", skillId: "builtin/page-report" },
+        reason: "Use the built-in report skill.",
+        confidence: 0.9
+      }),
+      JSON.stringify({
+        final: "Report generated.",
+        reason: "The skill completed.",
+        confidence: 0.9
+      })
+    );
+
+    const result = await runAgentTask({
+      task: "Create an HTML report for this page",
+      observe: async () => observation(),
+      act,
+      modelGateway,
+      skills: [{
+        id: "builtin/page-report",
+        name: "page-report",
+        description: "Create an HTML analysis report for the current page.",
+        skillMarkdown: "---\nname: page-report\ndescription: Create an HTML analysis report for the current page.\n---\nUse the report tool.",
+        enabled: true,
+        source: "builtin"
+      }]
+    });
+
+    expect(modelGateway.chat).toHaveBeenCalledWith(expect.arrayContaining([
+      expect.objectContaining({ role: "system", content: expect.stringContaining("Available installed skills") })
+    ]));
+    expect(act).toHaveBeenCalledWith({ type: "skill", skillId: "builtin/page-report" });
+    expect(result.finalText).toBe("Report generated.");
+  });
+
+  it("honors maxSteps with a hard cap of five", async () => {
+    const act = vi.fn().mockResolvedValue({ ok: true, status: "success", message: "Scrolled down" });
+    const modelGateway = gateway(
+      ...Array.from({ length: 8 }, () => JSON.stringify({
+        action: { type: "scroll", direction: "down", amount: 120 },
+        reason: "Need more page content.",
+        confidence: 0.7
+      }))
+    );
+
+    const result = await runAgentTask({
+      task: "Keep reading",
+      observe: async () => observation(),
+      act,
+      modelGateway,
+      maxSteps: 99
+    });
+
+    expect(modelGateway.chat).toHaveBeenCalledTimes(5);
+    expect(act).toHaveBeenCalledTimes(5);
+    expect(result.finalText).toContain("Stopped after 5 steps");
+    expect(result.events.at(-1)).toMatchObject({ type: "blocked" });
+  });
+
+  it("stops after an action failure with the failure reason", async () => {
+    const modelGateway = gateway(JSON.stringify({
+      action: { type: "click", selector: "#missing" },
+      reason: "Try to open the missing element.",
+      confidence: 0.6
+    }));
+
+    const result = await runAgentTask({
+      task: "Open missing",
+      observe: async () => observation(),
+      act: vi.fn().mockResolvedValue({ ok: false, status: "failed", message: "No element found for #missing" }),
+      modelGateway
+    });
+
+    expect(result.finalText).toBe("No element found for #missing");
+    expect(result.events.map((event) => event.type)).toEqual(["observe", "thought", "action", "action-result", "blocked"]);
+  });
+
+  it("blocks high-risk actions before calling DOM tools", async () => {
+    const act = vi.fn();
+    const modelGateway = gateway(JSON.stringify({
+      action: { type: "click", selector: "#buy" },
+      reason: "Submit the purchase.",
+      confidence: 0.76
+    }));
+
+    const result = await runAgentTask({
+      task: "Buy this item",
+      observe: async () => observation({
+        interactiveElements: [{ selector: "#buy", tagName: "button", label: "Buy now" }]
+      }),
+      act,
+      modelGateway
+    });
+
+    expect(act).not.toHaveBeenCalled();
+    expect(result.finalText).toContain("needs confirmation");
+    expect(result.events.at(-1)).toMatchObject({ type: "blocked", status: "needs_confirmation" });
+  });
+});

diff --git a/src/background/index.ts b/src/background/index.ts
new file mode 100644
index 0000000..32ba18a
--- /dev/null
+++ b/src/background/index.ts
@@ -0,0 +1,945 @@
+import { classifyTaskIntent, runAgentTask, runPageChat } from "../agent/runtime";
+import { builtInSkills, installSkillFromUrl, mergeSkills, parseSkillMarkdown, skillActionToBenchmarkRequest } from "../agent/skills";
+import { runBenchmarkTool, sanitizeReportHtml } from "./browserTools";
+import { createDebuggerTools, type DebuggerTarget } from "./debuggerTools";
+import { callModel } from "../model-gateway";
+import { appendCallLog, createCallLog } from "../shared/callLogs";
+import { appendDebugLog, createDebugLog } from "../shared/debugLogs";
+import {
+  buildGatewayStatus,
+  createGatewayError,
+  createGatewaySuccess,
+  debuggerAccessScopes,
+  GatewayProtocolError,
+  ensureGatewayAccess,
+  listGatewayModels,
+  normalizeGatewayError,
+  normalizeRequestedScopes,
+  resolveApprovedScopes,
+  requiredRunScopes
+} from "../shared/gateway";
+import { canUseDebuggerControl, grantSitePermission, revokeSitePermission, touchSitePermission } from "../shared/permissions";
+import { getActiveProvider, getSettings, normalizeSettings, saveSettings } from "../shared/storage";
+import type {
+  BrowserAgentRequest,
+  BrowserAgentResponse,
+  BenchmarkToolRequest,
+  BenchmarkToolResult,
+  ChatMessage,
+  ConversationMemory,
+  AgentAction,
+  AgentControlMode,
+  DebuggerAction,
+  DebuggerActionResult,
+  DomAction,
+  DomActionResult,
+  DomObservation,
+  ExtensionSettings,
+  PendingAccessRequest,
+  ProviderSettings,
+  Scope
+} from "../shared/types";
+
+type PendingAccessResolver = (result: { granted: boolean; origin: string; scopes: Scope[]; autoRun: boolean }) => void;
+type ChromeDebuggerTargetInfo = {
+  id?: string;
+  type?: string;
+  title?: string;
+  url?: string;
+  tabId?: number;
+  attached?: boolean;
+  extensionId?: string;
+  faviconUrl?: string;
+};
+type ResolvedDebuggerTarget = {
+  target: DebuggerTarget;
+  url?: string;
+  label: string;
+};
+type ExtensionFrameDiagnostic = {
+  tagName: string;
+  src: string;
+  extensionId: string;
+  ownedByThisExtension: boolean;
+};
+
+const pendingAccessRequests = new Map<string, {
+  request: PendingAccessRequest;
+  resolve: PendingAccessResolver;
+}>();
+let lastRegularTabId: number | undefined;
+
+chrome.runtime.onInstalled.addListener(() => {
+  chrome.sidePanel.setPanelBehavior({ openPanelOnActionClick: true }).catch(() => undefined);
+});
+
+function isHttpUrl(url: string | undefined): url is string {
+  return Boolean(url && /^https?:\/\//.test(url));
+}
+
+function tabUrlForDiagnostics(tab: chrome.tabs.Tab): string {
+  const pending = tab.pendingUrl ? ` pending=${tab.pendingUrl}` : "";
+  return `${tab.url || "unknown URL"}${pending}`;
+}
+
+function canInjectIntoTab(tab: chrome.tabs.Tab): boolean {
+  return Boolean(tab.id && isHttpUrl(tab.url) && (!tab.pendingUrl || isHttpUrl(tab.pendingUrl)));
+}
+
+async function getTabIfRegular(tabId: number | undefined): Promise<chrome.tabs.Tab | undefined> {
+  if (!tabId) return undefined;
+  try {
+    const tab = await chrome.tabs.get(tabId);
+    return canInjectIntoTab(tab) ? tab : undefined;
+  } catch {
+    return undefined;
+  }
+}
+
+async function findActiveRegularTabInNormalWindows(): Promise<chrome.tabs.Tab | undefined> {
+  const windows = await chrome.windows.getAll({ populate: true, windowTypes: ["normal"] });
+  for (const window of windows) {
+    const tab = window.tabs?.find((entry) => entry.active && canInjectIntoTab(entry));
+    if (tab) return tab;
+  }
+  return undefined;
+}
+
+function rememberRegularTab(tab: chrome.tabs.Tab): chrome.tabs.Tab {
+  if (tab.id && canInjectIntoTab(tab)) lastRegularTabId = tab.id;
+  return tab;
+}
+
+function isMissingReceiverError(error: unknown): boolean {
+  return error instanceof Error && error.message.includes("Receiving end does not exist");
+}
+
+async function sendContentMessage(tabId: number, message: unknown) {
+  return chrome.tabs.sendMessage(tabId, message);
+}
+
+async function ensureContentScript(tab: chrome.tabs.Tab): Promise<void> {
+  if (!tab.id) throw new Error("No active tab");
+  if (!canInjectIntoTab(tab)) {
+    throw new Error("Agenticify can only read regular http/https webpages. Open a webpage and try again.");
+  }
+
+  await chrome.scripting.executeScript({
+    target: { tabId: tab.id },
+    files: ["assets/content.js"]
+  });
+}
+
+async function observeTab(tab: chrome.tabs.Tab): Promise<DomObservation> {
+  if (!tab.id) throw new Error("No active tab");
+
+  let response: { ok?: boolean; observation?: DomObservation } | undefined;
+  try {
+    response = await sendContentMessage(tab.id, { target: "agenticify-content", type: "observe" });
+  } catch (error) {
+    if (!isMissingReceiverError(error)) throw error;
+    await ensureContentScript(tab);
+    response = await sendContentMessage(tab.id, { target: "agenticify-content", type: "observe" });
+  }
+
+  if (!response?.ok || !response.observation) throw new Error("Could not observe active page");
+  return response.observation;
+}
+
+function isDomAction(action: DomAction | { type: string }): action is DomAction {
+  return action.type === "click" || action.type === "type" || action.type === "scroll";
+}
+
+async function actTab(tab: chrome.tabs.Tab, action: DomAction | { type: string }): Promise<DomActionResult> {
+  if (!isDomAction(action)) {
+    return {
+      ok: false,
+      status: action.type === "debugger" ? "blocked" : "failed",
+      message: action.type === "debugger"
+        ? "Advanced control is gated in BrowserAgent Gateway v1."
+        : "This page action is not operable through DOM control."
+    };
+  }
+
+  if (!tab.id) throw new Error("No active tab");
+
+  let response: { ok?: boolean; result?: DomActionResult } | undefined;
+  try {
+    response = await sendContentMessage(tab.id, { target: "agenticify-content", type: "dom-action", action });
+  } catch (error) {
+    if (!isMissingReceiverError(error)) throw error;
+    await ensureContentScript(tab);
+    response = await sendContentMessage(tab.id, { target: "agenticify-content", type: "dom-action", action });
+  }
+
+  if (!response?.ok || !response.result) {
+    return { ok: false, status: "failed", message: "Could not execute DOM action on the active page" };
+  }
+  return response.result;
+}
+
+async function actAgentTab(tab: chrome.tabs.Tab, action: AgentAction): Promise<DomActionResult> {
+  if (action.type === "read") {
+    await observeTab(tab);
+    return { ok: true, status: "success", message: "Page context refreshed" };
+  }
+  if (action.type === "debugger") {
+    return { ok: false, status: "needs_confirmation", message: action.reason || "Debugger mode requires explicit permission" };
+  }
+  if (action.type === "skill") {
+    if (action.skillId === "builtin/skill-creator") {
+      const markdown = typeof action.input?.skillMarkdown === "string" ? action.input.skillMarkdown : "";
+      const draft = parseSkillMarkdown(markdown, { source: "manual" });
+      return {
+        ok: false,
+        status: "needs_confirmation",
+        message: "Review and install this skill.",
+        skillDraft: draft
+      };
+    }
+    const request = skillActionToBenchmarkRequest(action);
+    if (!request) return { ok: false, status: "failed", message: `Skill ${action.skillId} is not executable.` };
+    const result = await runBenchmarkToolForActiveTab(request, tab.id);
+    return { ok: true, status: "success", message: `Skill ${action.skillId} completed: ${result.title}` };
+  }
+  return actTab(tab, action);
+}
+
+async function getActiveTab(): Promise<chrome.tabs.Tab> {
+  const normalWindowTab = await findActiveRegularTabInNormalWindows();
+  if (normalWindowTab) return rememberRegularTab(normalWindowTab);
+
+  const [focusedTab] = await chrome.tabs.query({ active: true, lastFocusedWindow: true });
+  if (focusedTab?.id && canInjectIntoTab(focusedTab)) return rememberRegularTab(focusedTab);
+
+  const pageTab = await getTabIfRegular(lastRegularTabId);
+  if (!pageTab?.id) {
+    throw new Error("No active regular http/https tab. Select a webpage and try again.");
+  }
+  return rememberRegularTab(pageTab);
+}
