+  });
+  await persistLog(settings, {
+    source,
+    origin,
+    type: "run",
+    model: provider.defaultModel,
+    status: "success",
+    summary: task.slice(0, 120)
+  }, "Agent run", { origin, task, mode, intent, events: result.events });
+  return result;
