+                  <span>Copy</span>
+                </button>
+              </div>
+            </div>
+          </div>
+        ))}
+        {busy && (
+          <div className="timeline-row reasoning">
+            <div className="timeline-marker"><Loader2 size={12} /></div>
+            <div className="timeline-card working">
+              <div className="timeline-title"><span>{t.workingTitle}</span></div>
+              <div className="timeline-detail">{t.working}</div>
+            </div>
+          </div>
