+            <button
+              className="task-button benchmark-task-button"
+              disabled={busy || action.disabled}
+              key={action.label}
+              onClick={() => runBenchmark(action.request)}
+              title={!debuggerAllowed ? t.debuggerGateCopy : action.label}
+            >
+              <action.icon size={15} />
+              <span>{action.label}</span>
+            </button>
+          ))}
+        </div>
+        <div className="composer-shell">
+          <Textarea
+            className="composer-input"
+            placeholder={modelReady ? t.composerReady : t.composerNoModel}
+            value={input}
+            onChange={(event) => setInput(event.target.value)}
+            onKeyDown={(event) => {
+              if (event.key === "Enter" && !event.shiftKey) {
+                event.preventDefault();
+                runTask(input);
+              }
+            }}
+            disabled={!modelReady}
+          />
+          <div className="composer-footer">
+            <div className="model-selector-row">
+              <Select
+                value={activeModelSelection}
+                onValueChange={(value) => {
+                  const next = parseModelSelection(value);
